1145	        rc = ngx_ssl_set_session(pc->connection, ssl_session);
1146	
1147	        ngx_log_debug1(NGX_LOG_DEBUG_HTTP, pc->log, 0,
1148	                       "set session: %p", ssl_session);
1149	
1150	        ngx_ssl_free_session(ssl_session);
