1152	        return rc;
1153	    }
1154	#endif
1155	
1156	    ssl_session = peer->ssl_session;
1157	
1158	    rc = ngx_ssl_set_session(pc->connection, ssl_session);
1159	
1160	    ngx_log_debug1(NGX_LOG_DEBUG_HTTP, pc->log, 0,
